// Utility functions to get users by type
export const getDevUsersByType = (userTypes) => {
    return seededDevUsers.filter((user) => userTypes.includes(user.userType));
};
export const getAdminUsers = () => {
    return getDevUsersByType(['admin', 'moderator']);
};
export const getRescueUsers = () => {
    return getDevUsersByType(['rescue_staff']);
};
export const getAdopterUsers = () => {
    return getDevUsersByType(['adopter']);
};
// Get all users for admin/debug panels
export const getAllDevUsers = () => {
    return seededDevUsers;
};
